@chen369 No, can't say that I've run into that. I haven't adding any containers since running into the issue.

The only reason I noticed the host info message was because Portainer threw the error and can't move beyond it:
```
# curl --unix-socket /run/podman/podman.sock http://localhost/info
{"cause":"strconv.ParseFloat: parsing \"\": invalid syntax","message":"failed to obtain system memory info: error getting host info: unable to parse user value \"\": strconv.ParseFloat: parsing \"\": invalid syntax","response":500}
```

This looks like podman info does not like the data in /proc/stats on your system.
```
func getCPUUtilization() (*define.CPUUsage, error) {
	f, err := os.Open("/proc/stat")
	if err != nil {
		return nil, err
	}
	defer f.Close()
	scanner := bufio.NewScanner(f)
	// Read first line of /proc/stat that has entries for system ("cpu" line)
	for scanner.Scan() {
		break
	}
	// column 1 is user, column 3 is system, column 4 is idle
	stats := strings.Fields(scanner.Text())
	return statToPercent(stats)
}

func statToPercent(stats []string) (*define.CPUUsage, error) {
	userTotal, err := strconv.ParseFloat(stats[1], 64)
	if err != nil {
		return nil, errors.Wrapf(err, "unable to parse user value %q", stats[1])
	}
```
